const itemRender: UploadItemRender = (originNode, file, currFileList, actions) => {
  const { name, status, uid, url } = file;
  const index = currFileList.indexOf(file);
  return (
    <div className="custom-item-render">
      <span>{`uid:${uid} name: ${name} status: ${status} url: ${url}  ${index + 1}/${currFileList.length}`}</span>
      <span onClick={actions.remove} className="custom-item-render-action-remove" data-testid="remove">
        remove
      </span>
      <span onClick={actions.download} className="custom-item-render-action-download" data-testid="download">
        download
      </span>
      <span onClick={actions.preview} className="custom-item-render-action-preview" data-testid="preview">
        preview
      </span>
    </div>
  );
};

