export function Dragger() {
  const [fileList, setFileList] = useState<UploadFile[]>([]);
  const props = {
    fileList,
    accept: 'image/*',
    action: 'https://cloudapi.bytedance.net/faas/services/tth168/invoke/hello',
    onChange(info: { file: UploadFile; fileList: UploadFile[] }) {
      setFileList(() =>
        (info.fileList || []).map(item => ({
          ...item,
          url: item.status === 'success' ? item.response || item.url : '',
        })),
      );
    },
  };

  return (
    <Space style={{ width: '536px', padding: '30px' }} direction="vertical">
      <div>
        <p>拖拽上传 DEMO 01</p>
        <Upload.Dragger
          {...props}
          dragAreaConfig={{
            dragTitle: (
              <p style={{ margin: 0 }}>
                拖拽文件至此，或
                <Button type="text" color="primary">
                  选择文件上传
                </Button>
              </p>
            ),
            dragDescription: '请选择图片文件, 支持格式：JPG、PNG、JPEG',
          }}
        />
      </div>
      <div>
        <p>拖拽上传 DEMO 02</p>

        <Upload.Dragger {...props}>
          <div className="ud__upload-drag-area">
            <div className="ud__upload-drop-area-title">拖拽文件至此，或点击上传</div>
          </div>
        </Upload.Dragger>
      </div>
      <div>
        <p>拖拽上传 DEMO 03</p>

        <Upload.Dragger
          {...props}
          listType="simple-text"
          dragAreaConfig={{
            dragTitle: '点这里可以上传',
            dragDescription: '请选择图片文件',
          }}
        />
      </div>
      <div>
        <p>拖拽上传 DEMO 04</p>

        <Upload.Dragger
          {...props}
          listType="card"
          dragAreaConfig={{
            dragTitle: (
              <p style={{ margin: 0 }}>
                拖拽文件至此，或
                <Button type="text" color="primary">
                  选择文件上传
                </Button>
              </p>
            ),
            dragIcon: <AddColorful />,
            dragDescription: '请选择图片文件, 支持格式：JPG、PNG、JPEG',
          }}
        />
      </div>
      <div>
        <p>拖拽上传: 禁用态</p>

        <Upload.Dragger
          {...props}
          listType="card"
          disabled
          dragAreaConfig={{
            dragTitle: (
              <p style={{ margin: 0 }}>
                拖拽文件至此，或
                <Button type="text" color="primary" disabled>
                  选择文件上传
                </Button>
              </p>
            ),
            dragIcon: <AddColorful />,
            dragDescription: '请选择图片文件, 支持格式：JPG、PNG、JPEG',
          }}
        />
      </div>
    </Space>
  );
}

