export const FileListTypes = () => {
  const [list, setFileList] = useState<UploadFile[] | undefined>();

  function onChange({ fileList }: { fileList: UploadFile[] }) {
    const newFileList = fileList.map(file => {
      if (file.response) {
        file.url = file.response;
      }
      return file;
    });
    setFileList(newFileList);
  }

  function iconRender(file: UploadFile) {
    if (file.name.endsWith('pdf')) {
      return <FilePdfColorful />;
    } else if (file.name.endsWith('png')) {
      return <FileImageColorful />;
    }
  }
  return (
    <div style={{ width: '650px', padding: '30px' }}>
      {[null, 'text', 'simple-text', 'card'].map(type => (
        <div key={type}>
          <h1>ListType: {type || 'default'}</h1>
          <Upload
            defaultFileList={defaultFileList}
            iconRender={iconRender}
            action="https://cloudapi.bytedance.net/faas/services/tth168/invoke/hello"
            fileList={list}
            tips={
              <p
                style={{
                  lineHeight: '22px',
                  margin: 0,
                  fontSize: '14px',
                  color: '#8F959E',
                }}
              >
                请选择文件上传
              </p>
            }
            showUploadList={{
              showPreviewIcon: true,
              showDownloadIcon: true,
            }}
            onChange={onChange}
            listType={type as UploadListType}
          >
            <Button> 点击上传</Button>
          </Upload>
        </div>
      ))}
    </div>
  );
};

